626	    /// Pop the value on top of the stack and store it in the registry under
627	    /// the string `key`.
628	    ///
629	    /// C: `lua_setfield(L, LUA_REGISTRYINDEX, key)`.
630	    pub fn registry_set(&mut self, key: &[u8]) -> Result<(), LuaError> {
631	        set_field(self, LUA_REGISTRYINDEX, key)
632	    }
633	
634	    /// Create a new metatable in the registry under key `tname`. Leaves the
635	    /// new metatable on top of the stack and returns `true` when newly
636	    /// created. If `registry[tname]` already exists, leaves it on top of the
637	    /// stack and returns `false`.
638	    ///
639	    /// C: `LUALIB_API int luaL_newmetatable(lua_State *L, const char *tname)`
640	    pub fn new_metatable(&mut self, tname: &[u8]) -> Result<bool, LuaError> {
641	        if get_field(self, LUA_REGISTRYINDEX, tname)? != LuaType::Nil {
642	            return Ok(false);
643	        }
644	        self.pop_n(1);
645	        create_table(self, 0, 2)?;
646	        push_lstring(self, tname)?;
647	        set_field(self, -2, b"__name")?;
648	        push_value(self, -1);
649	        set_field(self, LUA_REGISTRYINDEX, tname)?;
650	        Ok(true)
651	    }
