657	    ///   `luaL_checkversion(L), luaL_newlibtable(L,l), luaL_setfuncs(L,l,0)`.
658	    /// `luaL_checkversion` is a no-op here (no ABI-version mismatch is
659	    /// possible inside the Rust port).
660	    pub fn new_lib(
661	        &mut self,
662	        funcs: &[(&[u8], LuaCFunction)],
663	    ) -> Result<(), LuaError> {
664	        create_table(self, 0, funcs.len() as i32)?;
665	        for (name, f) in funcs {
