/// Function table for `string` library.
///
/// C: `static const luaL_Reg strlib[]`
pub const STRING_LIB: &[(&[u8], lua_CFunction)] = &[
    (b"byte",     str_byte),
    (b"char",     str_char),
    (b"dump",     str_dump),
    (b"find",     str_find),
    (b"format",   str_format),
    (b"gmatch",   gmatch),
    (b"gsub",     str_gsub),
    (b"len",      str_len),
    (b"lower",    str_lower),
    (b"match",    str_match),
    (b"rep",      str_rep),
    (b"reverse",  str_reverse),
    (b"sub",      str_sub),
    (b"upper",    str_upper),
    (b"pack",     str_pack),
    (b"packsize", str_packsize),
    (b"unpack",   str_unpack),
];

/// Metamethods to install on the string metatable.
///
/// C: `static const luaL_Reg stringmetamethods[]`
pub const STRING_META_METHODS: &[(&[u8], lua_CFunction)] = &[
    (b"__add",  arith_add),
    (b"__sub",  arith_sub),
    (b"__mul",  arith_mul),
    (b"__mod",  arith_mod),
    (b"__pow",  arith_pow),
    (b"__div",  arith_div),
    (b"__idiv", arith_idiv),
    (b"__unm",  arith_unm),
];

/// Create the string metatable and set it as the metatable for all strings.
///
/// C: `static void createmetatable(lua_State *L)`
pub fn createmetatable(state: &mut LuaState) -> Result<(), LuaError> {
    eprintln!("[DEBUG createmetatable] called, top before={}", state.top_idx());
    // C: luaL_newlibtable(L, stringmetamethods);
    state.new_lib_table(STRING_META_METHODS)?;
    eprintln!("[DEBUG createmetatable] after new_lib_table, top={:?}, top val type={:?}", state.top_idx(), state.get_at(-1).clone());
    // C: luaL_setfuncs(L, stringmetamethods, 0);
    state.set_funcs(STRING_META_METHODS, 0)?;
    eprintln!("[DEBUG createmetatable] after set_funcs, top={}", state.top_idx());
    // C: lua_pushliteral(L, ""); lua_pushvalue(L, -2); lua_setmetatable(L, -2);
    state.push_string(b"")?;
    let mt = state.get_at(-2).clone();
    eprintln!("[DEBUG createmetatable] mt is {:?}", mt);
    state.push(mt);
    eprintln!("[DEBUG createmetatable] before set_metatable(-2), top={}, top val={:?}, obj at -2={:?}", state.top_idx(), state.get_at(-1).clone(), state.get_at(-2).clone());
    state.set_metatable(-2)?;
    eprintln!("[DEBUG createmetatable] after set_metatable, mt[STRING] is set");
    // C: lua_pop(L, 1);
    state.pop_n(1);
    // C: lua_pushvalue(L, -2); lua_setfield(L, -2, "__index");
    let strlib = state.get_at(-2).clone();
    state.push(strlib);
    state.set_field(-2, b"__index")?;
    // C: lua_pop(L, 1);
    state.pop_n(1);
    Ok(())
}

/// `luaopen_string` — open the string library.
///
/// C: `LUAMOD_API int luaopen_string(lua_State *L)`
pub fn luaopen_string(state: &mut LuaState) -> Result<usize, LuaError> {
    eprintln!("[DEBUG luaopen_string] entered");
    // C: luaL_newlib(L, strlib);
    state.new_lib(STRING_LIB)?;
    eprintln!("[DEBUG luaopen_string] after new_lib, calling createmetatable");
    createmetatable(state)?;
    eprintln!("[DEBUG luaopen_string] done");
    Ok(1)
}

