// C: #define L_ESC '%'
const L_ESC: u8 = b'%';

// C: #define SPECIALS "^$*+?.([%-"
const SPECIALS: &[u8] = b"^$*+?.([%-";

// C: #define CAP_UNFINISHED (-1)
const CAP_UNFINISHED: isize = -1;

// C: #define CAP_POSITION (-2)
const CAP_POSITION: isize = -2;

// C: #define MAX_ITEM 120
