// C: #define NB CHAR_BIT  (8)
const NB: u32 = 8;

// C: #define MC ((1 << NB) - 1)
const MC: u8 = 0xFF;

// C: #define SZINT ((int)sizeof(lua_Integer))
const SZINT: usize = 8; // sizeof(i64) == 8

// C: #define LUAL_PACKPADBYTE 0x00
